import numpy as np
import copy
from rory.core.security.cryptosystem.liu import Liu
from rory.core.utils.utils import Utils
from rory.core.utils.constants import Constants
import numpy.typing as npt
from typing import Tuple,List
from option import Result,Ok,Err,Option,NONE

"""
Description:
    Distributed skmeans algorithm.
    Divide skmeans into two parts. The first ends when client interaction is required. The second ends when the matrix S is zero.
"""
class SKMeans(object):

    """
    Description:
        The skmeans algorithm is started up to where the decryption of the matrix S is required
    """
    def run1(self, 
             status:int,
             k:int,
             m:int,
             encryptedMatrix:npt.NDArray,
             UDM:npt.NDArray,
            num_attributes:int,
            Cent_j:Option[List[List[float]]] = NONE

    )->Result[
            Tuple[npt.NDArray,List[List[float]],List[List[float]],List[int]],
            Exception
    ]:
        try:
            # D1Shape = Utils.getShapeOfMatrix(encryptedMatrix)
            C_empty = Utils.empty_cluster(k = k)
            
            # Cuando va iniciando SKMeans 
            if( status == Constants.ClusteringStatus.START ):
                C              = list(map(lambda x:[encryptedMatrix[x].tolist()],list(range(0,k)))) #add the first k records of D to C
                populate_clusters_result:Result[Tuple[List[List[int]], List[int]]] = Utils.populateClusters(
                    record_id         = k,
                    UDM               = UDM,
                    clusters          = C,
                    ciphertext_matrix = encryptedMatrix,
                )
                if populate_clusters_result.is_err:
                    return Err(populate_clusters_result.unwrap_err())
                
                C,label_vector = populate_clusters_result.unwrap()
                #Conjunto de los primeros k registros en D
                Cent_i:List[List[float]] = [encryptedMatrix[i] for i in range(k)] # initializes the set of centroids with the first record in D
                calculate_centroids_result = Utils.calculateCentroids(
                    clusters   = C,
                    k          = k,
                    attributes = num_attributes,
                    m          = m,
                )
                if calculate_centroids_result.is_err:
                    return Err(calculate_centroids_result.unwrap_err())
                
                _Cent_j = calculate_centroids_result.unwrap()
                S1 = self.generateShifMatrix(
                    k = k,
                    m = m,
                    a = num_attributes,
                    previous_centroids = Cent_i, 
                    current_centroids  = _Cent_j
                )
                label_vector = Utils.fillLabelVector(
                    label_vector = label_vector,
                    k            = k
                )
                return Ok((np.array(S1),Cent_i,_Cent_j,label_vector))
            else:
                _Cent_j  = Cent_j.unwrap()
                # kwargs.get("Cent_j") 
                populate_clusters_result = Utils.populateClusters(
                    record_id = 0,
                    UDM       = UDM,
                    clusters  = C_empty,
                    ciphertext_matrix = encryptedMatrix,
                    # centroids = _Cent_j,
                )
                if populate_clusters_result.is_err:
                    return Err(populate_clusters_result.unwrap_err())
                
                C, label_vector =  populate_clusters_result.unwrap()
                Cent_i = copy.copy(_Cent_j) #Reasigna los elementos de cent_j a cent_i
                calculate_centroids_result = Utils.calculateCentroids(
                    clusters   = C,
                    k          = k,
                    attributes = num_attributes,
                    m          = m,
                )
                if calculate_centroids_result.is_err:
                    return Err(calculate_centroids_result.unwrap_err())
                
                _Cent_j = calculate_centroids_result.unwrap()
                S1     = self.generateShifMatrix(
                    k = k,
                    m =m,
                    a = num_attributes,
                    previous_centroids = Cent_i,
                    current_centroids  = _Cent_j,
                )
                return  Ok((np.array(S1),Cent_i,_Cent_j,label_vector))
        except Exception as e:
            return Err(e)


    """
    description:  Update UDM matrix.
        A UDM matrix is a 3D matrix containing distances between the attribute values in each record
        and the corresponding attribute values in all other records.
    attributes:
        U: Updatable distance matrix
        Cent_i: previous set of centroids
        Cent_j: next set of centroids
        m: number of attributes of SK
    """
    def run_2(self,**kwargs):
        k      = kwargs.get("k",3)
        _U     = kwargs.get("UDM")
        U      = _U.tolist()
        a      = kwargs.get("attributes")
        _S     = kwargs.get("shiftMatrix")
        S      = _S.tolist()
        U1     = []
        for x in range(len(U)):
            U1.append([])
            for y in range(k):
                U1[x].append([])
                for z in range(a):
                    U1[x][y].append([])
                    if y > x: #Se revisa U completa.
                        U1[x][y][z] = ((-U[y][x][z] + S[y][z])) #Suma de cada elemento de U con S
                    else:
                        U1[x][y][z] = (U[x][y][z] + S[y][z]) #Suma de cada elemento de U con S
        return U1


    """
    Description:
        Generate encrypted shift matrix.
    """
    def generateShifMatrix(self,
                           previous_centroids:List[List[float]],
                            current_centroids:List[List[float]],
                            a:int = 3,
                            k:int=3,
                            m:int=3,
    )->List[List[float]]:
        # Cent_i = kwargs.get("previous_centroids")
        # Cent_j = kwargs.get("current_centroids")
        # k      = kwargs.get("k",3)
        # m      = kwargs.get("m",3)
        # a      = kwargs.get("a",3)
        S1:List[float]     = np.zeros((k,a,m)).tolist()
        for i in range(len(previous_centroids)):
            for j in range(len(previous_centroids[i])):
                S1[i][j] = Liu.subtract(
                    ciphertext_1 = previous_centroids[i][j], 
                    ciphertext_2 = current_centroids[i][j]
                    ) #Resta con el esquema de Liu	
        return S1